import{bQ as t,aL as a,u as i,G as e}from"./chunks/framework.D06dwy5q.js";const k=JSON.parse('{"title":"服务发现","description":"","frontmatter":{},"headers":[],"relativePath":"07.服务注册与配置中心/04-服务发现.md","filePath":"07.服务注册与配置中心/04-服务发现.md","lastUpdated":null}'),d={name:"07.服务注册与配置中心/04-服务发现.md"};function n(h,s,p,l,r,o){return a(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="服务发现" tabindex="-1">服务发现 <a class="header-anchor" href="#服务发现" aria-label="Permalink to &quot;服务发现&quot;">​</a></h1><p>配置中心管&quot;应用读什么配置&quot;，服务发现管&quot;一个服务名下面当前有哪些可用实例&quot;。Nacos 同时做这两件事，部署后要分别验证配置读取和服务注册两条链路。</p><h2 id="一、服务和实例——两个层级" tabindex="-1">一、服务和实例——两个层级 <a class="header-anchor" href="#一、服务和实例——两个层级" aria-label="Permalink to &quot;一、服务和实例——两个层级&quot;">​</a></h2><p>服务是逻辑名称，实例是具体的可连接地址。<code>order-service</code> 是服务名，它下面可以有多个实例：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20service%5B%22%E6%9C%8D%E5%8A%A1%3Cbr%2F%3Eorder-service%22%5D%20--%3E%20ins1%5B%22%E5%AE%9E%E4%BE%8B%3Cbr%2F%3E192.168.10.21%3A8080%22%5D%0A%20%20%20%20service%20--%3E%20ins2%5B%22%E5%AE%9E%E4%BE%8B%3Cbr%2F%3E192.168.10.22%3A8080%22%5D%0A%20%20%20%20service%20--%3E%20ins3%5B%22%E5%AE%9E%E4%BE%8B%3Cbr%2F%3E192.168.10.23%3A8080%22%5D%0A"></div><p>服务注册和查询时会反复出现这些字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td><code>serviceName</code></td><td>服务名</td><td><code>order-service</code></td></tr><tr><td><code>groupName</code></td><td>服务分组</td><td><code>DEFAULT_GROUP</code></td></tr><tr><td><code>ip</code></td><td>实例 IP</td><td><code>192.168.10.13</code></td></tr><tr><td><code>port</code></td><td>实例端口</td><td><code>18080</code></td></tr><tr><td><code>clusterName</code></td><td>集群名</td><td><code>DEFAULT</code></td></tr><tr><td><code>healthy</code></td><td>是否健康</td><td><code>true</code></td></tr><tr><td><code>weight</code></td><td>权重</td><td><code>1.0</code></td></tr><tr><td><code>metadata</code></td><td>附加信息</td><td><code>version=v1</code>、<code>zone=az1</code></td></tr></tbody></table><p>Nacos 返回的不只是 IP:PORT——还包含健康状态、权重、元数据。客户端可以基于这些信息做负载均衡（按权重分配请求）、灰度路由（按版本标签过滤）、就近访问（按 zone 筛选）。</p><h2 id="二、临时实例和持久实例" tabindex="-1">二、临时实例和持久实例 <a class="header-anchor" href="#二、临时实例和持久实例" aria-label="Permalink to &quot;二、临时实例和持久实例&quot;">​</a></h2><p><strong>临时实例</strong>：普通微服务最常用的方式。客户端 SDK 注册后持续发送心跳，Nacos 超过一定时间收不到心跳就标记不健康，再超时就摘除。服务进程停了，实例从注册中心消失，调用方后续不再拿到它。</p><p><strong>持久实例</strong>：由人通过 API 或控制台注册的一条固定记录，不依赖客户端心跳自动删除。适合少量固定后端或需要人工维护的服务条目。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 注册临时实例（默认）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sS</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;http://127.0.0.1:8848/nacos/v3/client/ns/instance&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;serviceName=ops-demo-service&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;groupName=DEFAULT_GROUP&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;ip=192.168.10.13&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;port=18080&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;username=nacos&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;password=nacos&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 注册持久实例</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sS</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;http://127.0.0.1:8848/nacos/v3/client/ns/instance&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;serviceName=ops-demo-persistent&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;groupName=DEFAULT_GROUP&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;ip=192.168.10.13&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;port=18080&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;ephemeral=false&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;username=nacos&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;password=nacos&#39;</span></span></code></pre></div><p>查询实例列表：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sS</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  &#39;http://127.0.0.1:8848/nacos/v3/client/ns/instance/list?serviceName=ops-demo-service&amp;groupName=DEFAULT_GROUP&amp;username=nacos&amp;password=nacos&#39;</span></span></code></pre></div><p>返回字段关注 <code>healthy</code>（是否健康）、<code>enabled</code>（是否启用）、<code>ephemeral</code>（是否临时实例）、<code>weight</code>（权重）。</p><p>命令行手工注册临时实例适合验证 API，但它没有真实客户端维持心跳——过一会儿实例会被标记不健康然后消失。这是正常的，不代表 Nacos 有问题。业务应用由 SDK 注册，SDK 处理心跳续约和断线重连。</p><h2 id="三、心跳——临时实例的存活依据" tabindex="-1">三、心跳——临时实例的存活依据 <a class="header-anchor" href="#三、心跳——临时实例的存活依据" aria-label="Permalink to &quot;三、心跳——临时实例的存活依据&quot;">​</a></h2><div class="mermaid-diagram" data-mermaid-code="sequenceDiagram%0A%20%20%20%20participant%20A%20as%20%22%E4%B8%9A%E5%8A%A1%E5%BA%94%E7%94%A8%22%0A%20%20%20%20participant%20N%20as%20%22Nacos%22%0A%0A%20%20%20%20A-%3E%3EN%3A%20%22%E6%B3%A8%E5%86%8C%E5%AE%9E%E4%BE%8B%22%0A%20%20%20%20loop%20%22%E8%BF%90%E8%A1%8C%E6%9C%9F%E9%97%B4%EF%BC%88%E9%BB%98%E8%AE%A4%E6%AF%8F%205%20%E7%A7%92%E4%B8%80%E6%AC%A1%E5%BF%83%E8%B7%B3%EF%BC%89%22%0A%20%20%20%20%20%20%20%20A-%3E%3EN%3A%20%22%E5%8F%91%E9%80%81%E5%BF%83%E8%B7%B3%20%2F%20%E4%BF%9D%E6%8C%81%E8%BF%9E%E6%8E%A5%22%0A%20%20%20%20end%0A%20%20%20%20N--%3E%3EA%3A%20%22%E6%8E%A8%E9%80%81%E6%9C%8D%E5%8A%A1%E5%88%97%E8%A1%A8%E5%8F%98%E6%9B%B4%22%0A"></div><p>临时实例依赖心跳。应用定期告诉 Nacos &quot;我还活着&quot;，Nacos 超过一段时间没收到心跳就把实例标记为不健康。常见故障场景：应用日志里反复报 Nacos 连接失败，几分钟后调用方开始找不到该服务。此时控制台服务名还在，但实例健康状态变了——&quot;服务名存在不等于调用正常&quot;，健康实例数和客户端日志才是关键。</p><p>心跳的几个关键时间参数：</p><table tabindex="0"><thead><tr><th>参数</th><th>默认值</th><th>含义</th></tr></thead><tbody><tr><td>心跳间隔</td><td>5s</td><td>客户端每隔多久发一次心跳</td></tr><tr><td>不健康阈值</td><td>15s</td><td>超过这个时间没收到心跳，标记为不健康</td></tr><tr><td>摘除阈值</td><td>30s</td><td>不健康状态持续超过这个时间，从列表里摘除</td></tr></tbody></table><p>网络偶尔波动、JVM GC 短暂暂停（几百毫秒到一两秒），通常不会导致心跳超时。持续 GC 长暂停（秒级甚至十几秒）、网络持续不通、应用线程池满载导致心跳线程没机会执行——这些才会触发摘除。</p><h2 id="四、权重和元数据" tabindex="-1">四、权重和元数据 <a class="header-anchor" href="#四、权重和元数据" aria-label="Permalink to &quot;四、权重和元数据&quot;">​</a></h2><p><strong>权重</strong>用于简单流量分配：权重越高，被客户端选中的概率越大。常见用途：</p><table tabindex="0"><thead><tr><th>场景</th><th>操作</th></tr></thead><tbody><tr><td>灰度少量流量</td><td>新版本实例权重调低（比如 0.1），老版本保持 1.0</td></tr><tr><td>下线前摘流量</td><td>权重调低到 0 或直接禁用实例</td></tr><tr><td>机器性能不同</td><td>高配机器给更高权重</td></tr></tbody></table><p><strong>元数据</strong>是实例上的键值对，常用于版本、机房、区域等标识：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>version=v2</span></span>
<span class="line"><span>zone=shanghai-a</span></span>
<span class="line"><span>role=gray</span></span></code></pre></div><p>只能放稳定、可解释的字段。临时排查随手加的标签如果没有清理，后续做灰度或路由判断时可能变成脏条件——一个实例的元数据里同时有 <code>version=v1</code> 和 <code>role=gray</code>，而灰度规则又是按 <code>role</code> 过滤，行为就和预期不一致了。</p><h2 id="五、客户端负载均衡——拿到列表之后" tabindex="-1">五、客户端负载均衡——拿到列表之后 <a class="header-anchor" href="#五、客户端负载均衡——拿到列表之后" aria-label="Permalink to &quot;五、客户端负载均衡——拿到列表之后&quot;">​</a></h2><p>应用从 Nacos 拿到实例列表后，怎么选择调用哪个实例，由客户端负载均衡策略决定，不是 Nacos 控制：</p><table tabindex="0"><thead><tr><th>策略</th><th>行为</th><th>适用场景</th></tr></thead><tbody><tr><td>轮询</td><td>按顺序逐个分配</td><td>实例配置相同、请求耗时相近</td></tr><tr><td>随机</td><td>随机选一个</td><td>简单场景</td></tr><tr><td>加权</td><td>按权重比例分配</td><td>灰度、机器性能不同</td></tr><tr><td>最少连接</td><td>选当前连接数最少的实例</td><td>请求耗时差异大</td></tr><tr><td>一致性哈希</td><td>同一请求参数总是路由到同一实例</td><td>有状态服务、缓存亲和性</td></tr></tbody></table><p>Nacos 提供实例列表和权重，具体的负载均衡算法由客户端框架（Spring Cloud LoadBalancer、Dubbo、gRPC 等）实现。</p><h2 id="六、服务发现的排查层次" tabindex="-1">六、服务发现的排查层次 <a class="header-anchor" href="#六、服务发现的排查层次" aria-label="Permalink to &quot;六、服务发现的排查层次&quot;">​</a></h2><p>&quot;服务发现失败&quot;按链路分层排查：</p><table tabindex="0"><thead><tr><th>层次</th><th>检查内容</th><th>常见问题</th></tr></thead><tbody><tr><td>应用侧</td><td>客户端是否成功注册，日志里有没有连接/鉴权异常</td><td><code>serviceName</code> 为空、连错 Nacos 地址</td></tr><tr><td>Nacos 服务侧</td><td>服务名、分组、命名空间是否一致</td><td>namespace 不一致导致&quot;查不到&quot;</td></tr><tr><td>实例侧</td><td>健康状态、IP/端口、权重</td><td>心跳断了、端口没有监听</td></tr><tr><td>网络侧</td><td>应用到 Nacos 的 <code>8848/9848</code> 是否通</td><td>防火墙只放了 8080</td></tr><tr><td>消费侧</td><td>调用方是否拿到最新实例列表，本地缓存是否过期</td><td>客户端缓存了旧列表</td></tr></tbody></table><p>出现&quot;服务不存在&quot;时，把调用方使用的 <code>namespace/group/serviceName</code> 写出来，再和控制台逐一比对。大量&quot;服务不存在&quot;的问题最后发现是：开发调的是 <code>dev</code> namespace，测试同学在 <code>test</code> namespace 的 Nacos 控制台查——看起来同名服务，实际上两个命名空间互不相通。</p><p>还有一个常见点：调用方在启动时就向 Nacos 订阅了服务列表，之后 Nacos 通过推送和定时拉取保持更新。但如果调用方因为网络问题断开了和 Nacos 的长连接，又没有及时重连，它可能拿着几分钟甚至更久之前的旧列表在调用——其中包括已经下线的实例。这种场景下，调用方日志里能看到&quot;连接 Nacos 失败&quot;或&quot;重连中&quot;的记录。</p>`,37)])])}const F=t(d,[["render",n]]);export{k as __pageData,F as default};
